import{c as a,Q as t,j as i,m as n}from"./chunks/framework.BXc4yaFE.js";const p=JSON.parse('{"title":"HeavySkill: Heavy Thinking as the Inner Skill in Agentic Harness","description":"","frontmatter":{"title":"HeavySkill: Heavy Thinking as the Inner Skill in Agentic Harness","authors":"Jianing Wang, Linsen Guo, Zhengyu Chen, Qi Guo, Hongyu Zang, Wenjie Shi, Haoxiang Ma, Xiangyu Xi, Xiaoyu Li, Wei Wang, Xunliang Cai","published":"2026-05-04T00:00:00.000Z","source":"https://arxiv.org/abs/2605.02396"},"headers":[],"relativePath":"research/papers/2026-05-04-heavyskill-heavy-thinking-inner-skill-2605-02396.md","filePath":"research/papers/2026-05-04-heavyskill-heavy-thinking-inner-skill-2605-02396.md","lastUpdated":1779901665000}'),r={name:"research/papers/2026-05-04-heavyskill-heavy-thinking-inner-skill-2605-02396.md"};function s(o,e,l,d,h,c){return t(),i("div",null,[...e[0]||(e[0]=[n('<h1 id="heavyskill-heavy-thinking-as-the-inner-skill-in-agentic-harness" tabindex="-1">HeavySkill: Heavy Thinking as the Inner Skill in Agentic Harness <a class="header-anchor" href="#heavyskill-heavy-thinking-as-the-inner-skill-in-agentic-harness" aria-label="Permalink to &quot;HeavySkill: Heavy Thinking as the Inner Skill in Agentic Harness&quot;">​</a></h1><p><strong>Authors</strong>: Jianing Wang, Linsen Guo, Zhengyu Chen, Qi Guo, Hongyu Zang, Wenjie Shi, Haoxiang Ma, Xiangyu Xi, Xiaoyu Li, Wei Wang, Xunliang Cai <strong>Published</strong>: May 4, 2026 <strong>Source</strong>: <a href="https://arxiv.org/abs/2605.02396" target="_blank" rel="noreferrer">https://arxiv.org/abs/2605.02396</a><strong>arXiv ID</strong>: 2605.02396 <strong>Categories</strong>: cs.AI <strong>Length</strong>: 18 pages, 10 figures</p><hr><h2 id="abstract" tabindex="-1">Abstract <a class="header-anchor" href="#abstract" aria-label="Permalink to &quot;Abstract&quot;">​</a></h2><p>HeavySkill proposes that <strong>heavy/deep thinking is both a minimal execution unit in orchestration harness AND an inner skill internalized within the model</strong> (not just an external orchestration layer). The two-stage pipeline (parallel reasoning → sequential deliberation) outperforms Best-of-N voting, with strong LLMs approaching theoretical Pass@K limits. The workflow is portable across any agent framework without modification.</p><hr><h2 id="core-thesis" tabindex="-1">Core Thesis <a class="header-anchor" href="#core-thesis" aria-label="Permalink to &quot;Core Thesis&quot;">​</a></h2><p>Heavy thinking is not just an external orchestration mechanism—it is an <strong>internalizable skill</strong> that can be learned, scaled, and deployed independently of fragile coordination layers.</p><p>Two unified views:</p><ol><li><strong>Orchestration view</strong>: Minimal execution unit schedulable by any agentic harness</li><li><strong>Internalization view</strong>: Parameterized skill embedded in model weights via RL</li></ol><hr><h2 id="methodology" tabindex="-1">Methodology <a class="header-anchor" href="#methodology" aria-label="Permalink to &quot;Methodology&quot;">​</a></h2><h3 id="two-stage-pipeline" tabindex="-1">Two-Stage Pipeline <a class="header-anchor" href="#two-stage-pipeline" aria-label="Permalink to &quot;Two-Stage Pipeline&quot;">​</a></h3><p><strong>Stage 1 — Parallel Reasoning</strong>: Generate K independent trajectories: <code>T_πθ(q,K) = {y₁, ..., yK}</code></p><p><strong>Stage 2 — Sequential Deliberation</strong>: Second LLM <code>πφ</code> processes serialized memory cache <code>xc</code> (pruned + shuffled trajectories) → produces synthesized output.</p><p><strong>Iterative Deliberation</strong> (N iterations): At iteration t, cache modified by concatenating prior deliberation outputs: <code>C(x^(t)) = T_πφ(x_c^(t-1), K^(t-1)) || x^(t-1)</code> → recursive refinement.</p><h3 id="readable-skill-for-agentic-harness" tabindex="-1">Readable Skill for Agentic Harness <a class="header-anchor" href="#readable-skill-for-agentic-harness" aria-label="Permalink to &quot;Readable Skill for Agentic Harness&quot;">​</a></h3><p>Four components of the portable skill:</p><ul><li><strong>Activation Conditions</strong>: Triggers on complex reasoning tasks</li><li><strong>Parallel Reasoning Protocol</strong>: Spawns K independent reasoning agents</li><li><strong>Deliberation Prompt</strong>: Templates guiding critical evaluation and synthesis (not naive concatenation)</li><li><strong>Output Constraints</strong>: Format requirements</li></ul><p>Functions across Claude Code, custom orchestrations, any harness—without modification.</p><hr><h2 id="experiments" tabindex="-1">Experiments <a class="header-anchor" href="#experiments" aria-label="Permalink to &quot;Experiments&quot;">​</a></h2><h3 id="models-tested" tabindex="-1">Models Tested <a class="header-anchor" href="#models-tested" aria-label="Permalink to &quot;Models Tested&quot;">​</a></h3><p><strong>Closed-weight</strong>: GPT-5-Thinking, Claude 4.5 Thinking, Gemini 3 Pro Preview <strong>Open-weight</strong>: R1-Distill-Qwen variants, Qwen3, DeepSeek R1, Kimi K2 Thinking, GLM 4.6, DeepSeek V3.2</p><p><strong>Parameters</strong>: Temperature=1.0, Top-p=0.95, K∈{8,16}, K^(1)=4</p><h3 id="metrics" tabindex="-1">Metrics <a class="header-anchor" href="#metrics" aria-label="Permalink to &quot;Metrics&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Metric</th><th>Definition</th></tr></thead><tbody><tr><td>M@K</td><td>Mean accuracy across K trajectories</td></tr><tr><td>P@K</td><td>Proportion with ≥1 correct trajectory</td></tr><tr><td>V@K</td><td>Majority voting accuracy</td></tr><tr><td>HM@K</td><td>Mean accuracy after deliberation</td></tr><tr><td>HP@K</td><td>Proportion with ≥1 correct summary</td></tr></tbody></table><hr><h2 id="key-results" tabindex="-1">Key Results <a class="header-anchor" href="#key-results" aria-label="Permalink to &quot;Key Results&quot;">​</a></h2><h3 id="stem-tasks-aime25-beyondaime-hmmt25-feb-gpqa-diamond" tabindex="-1">STEM Tasks (AIME25, BeyondAIME, HMMT25-Feb, GPQA-Diamond) <a class="header-anchor" href="#stem-tasks-aime25-beyondaime-hmmt25-feb-gpqa-diamond" aria-label="Permalink to &quot;STEM Tasks (AIME25, BeyondAIME, HMMT25-Feb, GPQA-Diamond)&quot;">​</a></h3><ol><li><p><strong>HM@4 consistently surpasses M@K</strong> across all models and benchmarks — deliberation yields positive gains over baseline trajectory quality</p></li><li><p><strong>Scaling validated</strong>: Performance improves with increased parallel trajectories (K) and deliberation — &quot;width&quot; (parallel) and &quot;depth&quot; (sequential) function as capability multipliers</p></li><li><p><strong>Outperforms voting</strong>: Heavy thinking frequently exceeds Vote@K — advantages pronounced on harder benchmarks (BeyondAIME, HMMT, GPQA-Diamond)</p></li><li><p><strong>Surpasses intrinsic boundaries</strong>: HP@4 exceeds P@K in ~50% of trials with frontier models — deliberation synthesizes cross-trajectory insights to generate correct solutions absent from any single trajectory</p></li></ol><h3 id="general-reasoning-livecodebench-arena-hard-ifeval-imo" tabindex="-1">General Reasoning (LiveCodeBench, Arena-Hard, IFEval, IMO) <a class="header-anchor" href="#general-reasoning-livecodebench-arena-hard-ifeval-imo" aria-label="Permalink to &quot;General Reasoning (LiveCodeBench, Arena-Hard, IFEval, IMO)&quot;">​</a></h3><ul><li><strong>LiveCodeBench</strong>: &quot;GPT-OSS-20B performance surges from 69.7% M@K to 85.5% HM@4&quot;</li><li><strong>Arena-Hard</strong>: Marginal gains only (subjective tasks less suited)</li><li><strong>IMO</strong>: GLM 4.6 achieves 86.0% HP@4 vs. 75.1% P@K</li></ul><p><strong>Conclusion</strong>: Heavy thinking excels at correctness-oriented tasks, not preference-oriented tasks.</p><hr><h2 id="further-analysis" tabindex="-1">Further Analysis <a class="header-anchor" href="#further-analysis" aria-label="Permalink to &quot;Further Analysis&quot;">​</a></h2><h3 id="sequential-deliberation-s-revision-capability-10k-queries-r1-distill-qwen-7b" tabindex="-1">Sequential Deliberation&#39;s Revision Capability (10K queries, R1-Distill-Qwen-7B) <a class="header-anchor" href="#sequential-deliberation-s-revision-capability-10k-queries-r1-distill-qwen-7b" aria-label="Permalink to &quot;Sequential Deliberation&#39;s Revision Capability (10K queries, R1-Distill-Qwen-7B)&quot;">​</a></h3><ul><li>Pass rate &lt;0.5: Heavy thinking corrects ~500 failures while leaving ~1,400 unresolved</li><li>Pass rate &gt;0.5: Success rate exceeds 98% despite ~30 degradations</li></ul><h3 id="optimal-deliberation-model" tabindex="-1">Optimal Deliberation Model <a class="header-anchor" href="#optimal-deliberation-model" aria-label="Permalink to &quot;Optimal Deliberation Model&quot;">​</a></h3><p>Counter-intuitive finding: Qwen2.5-32B-Instruct (weaker independent reasoner) yields expected gains as synthesizer. <strong>Deliberation relies on analysis/synthesis ability, not peak reasoning power.</strong></p><h3 id="iterative-deliberation-trade-off" tabindex="-1">Iterative Deliberation Trade-off <a class="header-anchor" href="#iterative-deliberation-trade-off" aria-label="Permalink to &quot;Iterative Deliberation Trade-off&quot;">​</a></h3><ul><li>HM@K consistently improves with more iterations</li><li>HP@K degrades: &quot;subsequent steps susceptible to interference from earlier stages&quot;</li><li>Trade-off between depth and information consistency</li></ul><h3 id="tool-use-adaptation-qwen3-8b-32b-gpt-oss-20b" tabindex="-1">Tool-Use Adaptation (Qwen3-8B/32B, GPT-OSS-20B) <a class="header-anchor" href="#tool-use-adaptation-qwen3-8b-32b-gpt-oss-20b" aria-label="Permalink to &quot;Tool-Use Adaptation (Qwen3-8B/32B, GPT-OSS-20B)&quot;">​</a></h3><p>&quot;GPT-OSS-20B achieves 90.0% under heavy thinking vs. 83.3% voting on AIME25&quot; — deliberation effectively leverages tool execution feedback.</p><hr><h2 id="rlvr-advancement-appendix-b" tabindex="-1">RLVR Advancement (Appendix B) <a class="header-anchor" href="#rlvr-advancement-appendix-b" aria-label="Permalink to &quot;RLVR Advancement (Appendix B)&quot;">​</a></h2><p>~10% HM@4 improvement in initial 100 training steps. Stability issues at K=16 due to maximum sequence length limitations.</p><p><strong>Trajectory selection</strong>: Max-Answer-Num (voting-based) significantly outperforms random sampling, max-diversity, and max-length approaches.</p><hr><h2 id="workspace-relevance" tabindex="-1">Workspace Relevance <a class="header-anchor" href="#workspace-relevance" aria-label="Permalink to &quot;Workspace Relevance&quot;">​</a></h2><p>Directly validates <code>opus-pilot</code> <strong>Mechanism #2 (Parallel Hypotheses + Synthesis)</strong>: N=3 parallel candidates → synthesis is the same two-stage pattern. Paper confirms this is superior to Best-of-N selection.</p><p>For <code>haiku-pilot</code> / escalation gates: if the model has internalized heavy thinking (via RL training), the &quot;escalate to Opus for deep reasoning&quot; gate should account for whether the base model has this capability built in.</p>',52)])])}const u=a(r,[["render",s]]);export{p as __pageData,u as default};
